import React, { useState } from 'react';
import {
  Container,
  Box,
  Typography,
  Grid,
  Card,
  CardContent,
  TextField,
  Button,
  FormControl,
  InputLabel,
  Select,
  MenuItem,
  Chip,
  IconButton,
  Alert
} from '@mui/material';
import {
  AddPhotoAlternate as AddPhotoIcon,
  Delete as DeleteIcon,
  CloudUpload as UploadIcon
} from '@mui/icons-material';
import { useListings } from '../context/ListingContext';

const Add = () => {
  const { addListing } = useListings();
  const [formData, setFormData] = useState({
    title: '',
    description: '',
    category: '',
    price_per_day: '',
    location: '',
    availability: []
  });
  const [images, setImages] = useState([]);
  const [previewUrls, setPreviewUrls] = useState([]);
  const [success, setSuccess] = useState(false);

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
  };

  const handleImageUpload = (e) => {
    const files = Array.from(e.target.files);
    setImages(prev => [...prev, ...files]);

    // Create preview URLs
    const newPreviewUrls = files.map(file => URL.createObjectURL(file));
    setPreviewUrls(prev => [...prev, ...newPreviewUrls]);

    // Show success message
    setSuccess(true);
    setTimeout(() => setSuccess(false), 3000);
  };

  const removeImage = (index) => {
    setImages(prev => prev.filter((_, i) => i !== index));
    setPreviewUrls(prev => prev.filter((_, i) => i !== index));
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    // In a real app, you would upload images first and get URLs
    // For now, we'll use placeholder images
    const newListing = {
      ...formData,
      price_per_day: parseFloat(formData.price_per_day),
      image: previewUrls[0] || "https://images.unsplash.com/photo-1516035069371-29a1b244cc32?auto=format&fit=crop&w=400&h=300"
    };

    addListing(newListing);
    setSuccess(true);

    // Reset form
    setFormData({
      title: '',
      description: '',
      category: '',
      price_per_day: '',
      location: '',
      availability: []
    });
    setImages([]);
    setPreviewUrls([]);

    // Hide success message after 3 seconds
    setTimeout(() => setSuccess(false), 3000);
  };

  return (
    <Container maxWidth="lg">
      <Box sx={{ mt: 4, mb: 4 }}>
        <Typography 
          variant="h4" 
          sx={{ 
            fontWeight: 700, 
            color: '#008080',
            mb: 3,
            textAlign: 'center'
          }}
        >
          Add New Listing
        </Typography>

        {success && (
          <Alert 
            severity="success" 
            sx={{ 
              mb: 3, 
              borderRadius: '12px',
              '& .MuiAlert-icon': {
                color: '#2E7D32'
              },
              '& .MuiAlert-message': {
                color: '#2E7D32',
                fontWeight: 500
              }
            }}
          >
            Listing added successfully!
          </Alert>
        )}

        <Card sx={{ 
          borderRadius: '16px', 
          boxShadow: '0 4px 12px rgba(0, 128, 128, 0.1)',
          maxWidth: '800px',
          margin: '0 auto'
        }}>
          <CardContent>
            <form onSubmit={handleSubmit}>
              <Grid container spacing={3}>
                <Grid item xs={12}>
                  <TextField
                    fullWidth
                    label="Title"
                    name="title"
                    value={formData.title}
                    onChange={handleInputChange}
                    required
                    variant="outlined"
                    sx={{ mb: 2 }}
                  />
                </Grid>

                <Grid item xs={12}>
                  <TextField
                    fullWidth
                    label="Description"
                    name="description"
                    value={formData.description}
                    onChange={handleInputChange}
                    required
                    multiline
                    rows={4}
                    variant="outlined"
                    sx={{ mb: 2 }}
                  />
                </Grid>

                <Grid item xs={12} md={6}>
                  <FormControl fullWidth sx={{ mb: 2 }}>
                    <InputLabel>Category</InputLabel>
                    <Select
                      name="category"
                      value={formData.category}
                      label="Category"
                      onChange={handleInputChange}
                      required
                    >
                      <MenuItem value="Electronics">Electronics</MenuItem>
                      <MenuItem value="Sports">Sports</MenuItem>
                      <MenuItem value="Tools">Tools</MenuItem>
                      <MenuItem value="Fashion">Fashion</MenuItem>
                      <MenuItem value="Home">Home</MenuItem>
                      <MenuItem value="Other">Other</MenuItem>
                    </Select>
                  </FormControl>
                </Grid>

                <Grid item xs={12} md={6}>
                  <TextField
                    fullWidth
                    label="Price per day (€)"
                    name="price_per_day"
                    value={formData.price_per_day}
                    onChange={handleInputChange}
                    required
                    type="number"
                    variant="outlined"
                    sx={{ mb: 2 }}
                  />
                </Grid>

                <Grid item xs={12}>
                  <TextField
                    fullWidth
                    label="Location"
                    name="location"
                    value={formData.location}
                    onChange={handleInputChange}
                    required
                    variant="outlined"
                    sx={{ mb: 2 }}
                  />
                </Grid>

                <Grid item xs={12}>
                  <Typography variant="h6" sx={{ mb: 2, color: '#008080' }}>
                    Images
                  </Typography>

                  <Box sx={{ 
                    border: '2px dashed #E0E0E0', 
                    borderRadius: '12px', 
                    p: 3, 
                    textAlign: 'center',
                    mb: 2
                  }}>
                    <input
                      accept="image/*"
                      style={{ display: 'none' }}
                      id="image-upload"
                      multiple
                      type="file"
                      onChange={handleImageUpload}
                    />
                    <label htmlFor="image-upload">
                      <Button 
                        variant="outlined" 
                        component="span"
                        sx={{ 
                          borderColor: '#008080',
                          color: '#008080',
                          borderRadius: '9999px',
                          fontWeight: 600,
                          '&:hover': {
                            backgroundColor: 'rgba(0, 128, 128, 0.1)',
                            borderColor: '#006666',
                          }
                        }}
                        startIcon={<UploadIcon />}
                      >
                        Upload Images
                      </Button>
                    </label>
                    <Typography variant="body2" sx={{ mt: 1, color: '#5A7D8C' }}>
                      or drag and drop images here
                    </Typography>
                  </Box>

                  <Box sx={{ display: 'flex', flexWrap: 'wrap', gap: 2 }}>
                    {previewUrls.map((url, index) => (
                      <Box key={index} sx={{ position: 'relative' }}>
                        <img 
                          src={url} 
                          alt={`Preview ${index}`} 
                          style={{ 
                            width: '100px', 
                            height: '100px', 
                            objectFit: 'cover', 
                            borderRadius: '8px' 
                          }} 
                        />
                        <IconButton 
                          size="small" 
                          sx={{ 
                            position: 'absolute', 
                            top: -8, 
                            right: -8, 
                            backgroundColor: 'white',
                            '&:hover': {
                              backgroundColor: '#FFEBEE'
                            }
                          }}
                          onClick={() => removeImage(index)}
                        >
                          <DeleteIcon fontSize="small" sx={{ color: '#C62828' }} />
                        </IconButton>
                      </Box>
                    ))}
                  </Box>
                </Grid>

                <Grid item xs={12}>
                  <Button 
                    type="submit"
                    variant="contained" 
                    fullWidth
                    sx={{ 
                      mt: 2,
                      backgroundColor: '#008080',
                      color: 'white',
                      borderRadius: '9999px',
                      fontWeight: 600,
                      py: 1.5,
                      fontSize: '1rem',
                      '&:hover': {
                        backgroundColor: '#006666',
                      }
                    }}
                  >
                    Add Listing
                  </Button>
                </Grid>
              </Grid>
            </form>
          </CardContent>
        </Card>
      </Box>
    </Container>
  );
};

export default Add;
